ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?episodes a :Episodes .
    ?directors a :Directors .
    ?episodes p:hasDirectors ?directors .
    ?directors p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?episodes a :Episodes .
    ?editors a :Editors .
    ?episodes p:hasEditors ?editors .
    ?editors p:name ?name .
    ?episodes p:Title ?title_f .
    FILTER(STR(?title_f) = "Episode 2")
    BIND(?name AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?episodes a :Episodes .
    ?directors a :Directors .
    ?episodes p:hasDirectors ?directors .
    ?directors p:name ?name .
    ?episodes p:DirectorID ?directorid_f .
    FILTER((STR(?directorid_f) = "2" || STR(?directorid_f) = "2.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?episodes a :Episodes .
    ?editors a :Editors .
    ?episodes p:hasEditors ?editors .
    ?editors p:name ?name .
    ?episodes p:Title ?title_f .
    FILTER(STR(?title_f) = "Episode 2")
    BIND(?name AS ?o0)
  }
} }
}
